image.asymptote:
// 3-D: PreTeXt renders this to an interactive WebGL figure for the web target.
import three;
size(11cm);
currentprojection=orthographic(5,2.2,3.4);

triple o=(0,0,0), u=(2,0,0), v=(1,3,0), w=(1,1,4);
triple uv=u+v, uw=u+w, vw=v+w, uvw=u+v+w;

// six faces of the parallelepiped, semi-transparent
pen face=gray(0.6)+opacity(0.32);
draw(surface(o--u--uv--v--cycle), face);
draw(surface(w--uw--uvw--vw--cycle), face);
draw(surface(o--u--uw--w--cycle), face);
draw(surface(v--uv--uvw--vw--cycle), face);
draw(surface(o--v--vw--w--cycle), face);
draw(surface(u--uv--uvw--uw--cycle), face);

// edges
pen edge=black+linewidth(0.5pt);
draw(o--u--uv--v--cycle, edge);
draw(w--uw--uvw--vw--cycle, edge);
draw(o--w, edge); draw(u--uw, edge); draw(v--vw, edge); draw(uv--uvw, edge);

// the three spanning vectors
draw(o--u, blue+linewidth(1.6pt), Arrow3);
draw(o--v, heavygreen+linewidth(1.6pt), Arrow3);
draw(o--w, red+linewidth(1.6pt), Arrow3);
label("$\mathbf u$", u, S);
label("$\mathbf v$", v, S+2E);
label("$\mathbf w$", w, 2W);
label("volume $=24$", (uvw)/2, 3N);
dot(o);

statement.p:
The scalar triple product of three vectors in \mathbb R^3 is

\boxed{
    \mathbf u\cdot(\mathbf v\times\mathbf w).
}

It is equal to the determinant
\det[\mathbf u\ \mathbf v\ \mathbf w].

The signed volume of the parallelepiped spanned by
\mathbf u,\mathbf v,\mathbf w
is

\boxed{
    \mathbf u\cdot(\mathbf v\times\mathbf w).
}

The ordinary volume is

\boxed{
    \left|\mathbf u\cdot(\mathbf v\times\mathbf w)\right|.
}
